const { righteous, montserrat, icons } = await loadFonts();
const { name, address, phone, logo } = brandData;
const scale = getScale(width, height);
const paint = Skia.Paint();

// 1. Premium floating glassmorphic container box anchored securely at the bottom
const cardW = width - (80 * scale);
const cardH = 170 * scale;
const cardX = 40 * scale;
const cardY = height - cardH - (50 * scale);
const radius = 24 * scale;

// Intentionally soft, diffuse dropshadow for premium structural depth
paint.setColor(Skia.Color('black'));
paint.setAlphaf(0.15);
canvas.drawRRect(Skia.RRectXY({ x: cardX, y: cardY + (6 * scale), width: cardW, height: cardH }, radius, radius), paint);

// Main Frosted Glass ultra-opaque white canvas backing
paint.setColor(Skia.Color('white'));
paint.setAlphaf(0.95);
canvas.drawRRect(Skia.RRectXY({ x: cardX, y: cardY, width: cardW, height: cardH }, radius, radius), paint);

let contentX = cardX + (40 * scale);

// 2. High-precision circular mask ring clip for official retail logo asset
if (logo) {
  const lSize = 90 * scale;
  const lY = cardY + (cardH - lSize) / 2;

  paint.setColor(Skia.Color('#1E293B')); // Premium deep slate border mask
  paint.setAlphaf(1);
  canvas.drawCircle(contentX + lSize / 2, lY + lSize / 2, lSize / 2 + 3 * scale, paint);

  canvas.save();
  const clip = Skia.Path.Make().addCircle(contentX + lSize / 2, lY + lSize / 2, lSize / 2);
  canvas.clipPath(clip, 1, true);

  const { width: lW, height: lH } = getLogoDimensions(logo);
  const s = Math.max(lSize / lW, lSize / lH);
  drawLogo(canvas, logo, contentX - ((lW * s) - lSize) / 2, lY - ((lH * s) - lSize) / 2, lW * s, lH * s);
  canvas.restore();

  contentX += lSize + (30 * scale);
}

