const directoryFont = montserrat;
directoryFont.setSize(22 * scale);

if (address) {
  drawIcon(canvas, 'location', contentX, cardY + 90 * scale, 22 * scale, paint, icons);
  drawTextLeft(canvas, address, contentX + (32 * scale), cardY + 110 * scale, directoryFont, paint, cardW - 150 * scale);
}

drawIcon(canvas, 'call', contentX, cardY + 125 * scale, 22 * scale, paint, icons);
drawTextLeft(canvas, `ORDER: ${phone}`, contentX + (32 * scale), cardY + 145 * scale, directoryFont, paint, cardW - 150 * scale);

return ["name", "address", "phone"];

